<div class="cv-container-compact">

  <!-- En-tête du module principal -->
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3>
        <i class="bi bi-sliders" style="color: #0ea5e9;"></i>
        Gestionnaire de Profil Professionnel
      </h3>

      <p style="margin: 2px 0 0 0; color: #64748b; font-size: 13px;">
        Remplissez vos informations à gauche et visualisez votre CV mis en forme à droite.
      </p>
    </div>
  </div>

  @if (successMessage) {
    <div class="alert-box-compact alert-success">
      {{ successMessage }}
    </div>
  }

  <!-- ================= LAYOUT PRINCIPAL ================= -->
  <div class="cv-split-layout">

    <!-- ===================================================== -->
    <!-- PANNEAU GAUCHE : FORMULAIRE -->
    <!-- ===================================================== -->
    <div class="cv-panel-card scrollable-form-panel">

      <form (ngSubmit)="onSaveCV($event)" class="compact-form-grid-vertical">

        <!-- Métier & Résumé -->
        <div class="form-section-title-inline">
          <i class="bi bi-person-badge"></i>
          Métier & Accroche
        </div>

        <div class="form-group-compact">
          <label>Titre du poste recherché *</label>

          <input
            type="text"
            name="cv_title"
            [(ngModel)]="cvData.title"
            placeholder="Ex: Développeur Fullstack Angular"
            required
          >
        </div>

        <div class="form-group-compact">
          <label>Résumé / Accroche professionnelle *</label>

          <textarea
            name="summary"
            [(ngModel)]="cvData.summary"
            rows="2"
            placeholder="Ex: Développeur motivé spécialisé dans..."
            required
          ></textarea>
        </div>

        <!-- Compétences -->
        <div class="form-section-title-inline" style="margin-top: 10px;">
          <i class="bi bi-tags"></i>
          Compétences
        </div>

        <div class="form-group-compact">
          <label>Compétences clés *</label>

          <input
            type="text"
            name="skills"
            [(ngModel)]="cvData.skills"
            placeholder="Ex: Angular, TypeScript, SQL, Docker"
            required
          >
        </div>

        <!-- Centres d'intérêt -->
        <div class="form-section-title-inline" style="margin-top: 10px;">
          <i class="bi bi-heart-fill"></i>
          Centres d'intérêt
        </div>

        <div class="form-group-compact">
          <label>Vos intérêts</label>

          <input
            type="text"
            name="interests"
            [(ngModel)]="cvData.interests"
            placeholder="Ex: Lecture, Football, Gaming, Voyages"
          >
        </div>

        <!-- EXPERIENCES -->
        <div class="form-section-title-inline-flex" style="margin-top: 10px;">

          <span>
            <i class="bi bi-briefcase"></i>
            Expériences Professionnelles
          </span>

          <button
            type="button"
            class="btn-add-dynamic"
            (click)="addExperience()"
          >
            <i class="bi bi-plus-circle-fill"></i>
            Ajouter
          </button>
        </div>

        @for (exp of cvData.experiences; track $index) {

          <div class="dynamic-entry-card">

            <div class="dynamic-entry-header">
              <span>Expérience #{{ $index + 1 }}</span>

              <button
                type="button"
                class="btn-remove-dynamic"
                (click)="removeExperience($index)"
              >
                <i class="bi bi-trash3-fill"></i>
              </button>
            </div>

            <div class="dynamic-fields-grid">

              <input
                type="text"
                name="exp_title_{{$index}}"
                [(ngModel)]="exp.job_title"
                placeholder="Poste"
                required
              >

              <input
                type="text"
                name="exp_comp_{{$index}}"
                [(ngModel)]="exp.company"
                placeholder="Entreprise"
                required
              >

              <input
                type="text"
                name="exp_date_{{$index}}"
                [(ngModel)]="exp.duration"
                placeholder="Durée"
                required
              >

              <textarea
                name="exp_desc_{{$index}}"
                [(ngModel)]="exp.description"
                rows="2"
                class="span-all-field"
                placeholder="Missions accomplies..."
                required
              ></textarea>

            </div>
          </div>
        }

        <!-- FORMATIONS -->
        <div class="form-section-title-inline-flex" style="margin-top: 10px;">

          <span>
            <i class="bi bi-mortarboard"></i>
            Formations & Études
          </span>

          <button
            type="button"
            class="btn-add-dynamic"
            (click)="addEducation()"
          >
            <i class="bi bi-plus-circle-fill"></i>
            Ajouter
          </button>
        </div>

        @for (edu of cvData.educations; track $index) {

          <div class="dynamic-entry-card">

            <div class="dynamic-entry-header">
              <span>Formation #{{ $index + 1 }}</span>

              <button
                type="button"
                class="btn-remove-dynamic"
                (click)="removeEducation($index)"
              >
                <i class="bi bi-trash3-fill"></i>
              </button>
            </div>

            <div class="dynamic-fields-grid">

              <input
                type="text"
                name="edu_deg_{{$index}}"
                [(ngModel)]="edu.degree"
                placeholder="Diplôme"
                required
              >

              <input
                type="text"
                name="edu_sch_{{$index}}"
                [(ngModel)]="edu.school"
                placeholder="Université"
                required
              >

              <input
                type="text"
                name="edu_year_{{$index}}"
                [(ngModel)]="edu.year"
                placeholder="Année"
                required
              >

            </div>
          </div>
        }

        <!-- Bouton -->
        <div class="form-actions-compact">

          <button
            type="submit"
            class="btn-save-cv-compact"
            [disabled]="isSaving"
          >
            <i class="bi bi-cloud-arrow-up-fill"></i>
            Enregistrer mon CV
          </button>

        </div>

      </form>
    </div>

    <!-- ===================================================== -->
    <!-- PANNEAU DROIT : APERÇU CV -->
    <!-- ===================================================== -->
    <div class="cv-right-layout-cards scrollable-form-panel">

      <!-- ================= CARTE IDENTITÉ ================= -->
      <div class="cv-panel-card-inner-box">

        <div class="profile-header-pro">

          <!-- Avatar -->
          <div class="cv-avatar-wrapper-pro">

            @if (avatarUrl) {
              <img [src]="avatarUrl" alt="Photo Candidat">
            } @else {
              <i
                class="bi bi-camera-fill"
                style="font-size: 24px; color: #94a3b8;"
              ></i>
            }

          </div>

          <!-- Infos -->
          <div class="profile-info-pro">

            <h4>{{ candidateName }}</h4>

            <span class="job-title-subtext">
              {{ cvData.title || 'Intitulé du poste recherché' }}
            </span>

          </div>

        </div>

        <!-- Coordonnées -->
        <div class="contact-info-grid-pro">

          <div class="contact-badge-item">
            <i class="bi bi-envelope-fill"></i>
            {{ candidateContact.email || 'Email non renseigné' }}
          </div>

          <div class="contact-badge-item">
            <i class="bi bi-telephone-fill"></i>
            {{ candidateContact.phone || 'Téléphone non renseigné' }}
          </div>

          <div class="contact-badge-item span-full-badge">
            <i class="bi bi-geo-alt-fill"></i>
            {{ candidateContact.address || 'Adresse non renseignée' }}
          </div>

        </div>

        <!-- Résumé -->
        <div class="resume-block-pro-card">

          <strong>Résumé professionnel</strong>

          <p>
            {{
              cvData.summary ||
              'Votre accroche professionnelle s’affichera ici dès que vous commencerez à taper...'
            }}
          </p>

        </div>

      </div>

      <!-- ================= CARTE PARCOURS ================= -->
      <div class="cv-panel-card-inner-box" style="margin-top: 20px;">

        <!-- EXPERIENCES -->
        <div class="preview-section-item">

          <span class="preview-section-label">
            <i class="bi bi-briefcase-fill"></i>
            Expériences Professionnelles
          </span>

          @if (cvData.experiences.length > 0) {

            @for (exp of cvData.experiences; track exp) {

              <div class="preview-block-pro">

                <div class="preview-row-pro">

                  <strong>
                    {{ exp.job_title || 'Poste occupé' }}
                  </strong>

                  <span class="date-tag-pro">
                    {{ exp.duration || 'Période' }}
                  </span>

                </div>

                <span class="sub-title-pro">
                  🏢 {{ exp.company || 'Entreprise' }}
                </span>

                <p class="desc-text-pro">
                  {{ exp.description }}
                </p>

              </div>
            }

          } @else {

            <span class="empty-text-italic">
              Aucune expérience professionnelle ajoutée.
            </span>

          }

        </div>

        <!-- FORMATIONS -->
        <div class="preview-section-item" style="margin-top: 20px;">

          <span class="preview-section-label">
            <i class="bi bi-mortarboard-fill"></i>
            Formations & Études
          </span>

          @if (cvData.educations.length > 0) {

            @for (edu of cvData.educations; track edu) {

              <div class="preview-block-pro">

                <div class="preview-row-pro">

                  <strong>
                    {{ edu.degree || 'Diplôme obtenu / visé' }}
                  </strong>

                  <span class="date-tag-pro">
                    {{ edu.year || 'Année' }}
                  </span>

                </div>

                <span class="sub-title-pro">
                  🎓 {{ edu.school || 'Établissement / École' }}
                </span>

              </div>
            }

          } @else {

            <span class="empty-text-italic">
              Aucune formation renseignée.
            </span>

          }

        </div>

        <!-- COMPÉTENCES -->
        <div class="preview-section-item" style="margin-top: 20px;">

          <span class="preview-section-label">
            <i class="bi bi-star-fill"></i>
            Compétences
          </span>

          <div class="cv-tags-container">

            @if (cvData.skills) {

              @for (skill of getSkillsArray(); track skill) {
                <span class="skill-tag-preview-pro">
                  {{ skill.trim() }}
                </span>
              }

            } @else {

              <span class="empty-text-italic">
                Aucune compétence saisie.
              </span>

            }

          </div>

        </div>

        <!-- INTERETS -->
        <div class="preview-section-item" style="margin-top: 20px;">

          <span class="preview-section-label">
            <i class="bi bi-heart-fill"></i>
            Centres d'intérêt
          </span>

          <div class="cv-tags-container">

            @if (cvData.interests) {

              @for (interest of getInterestsArray(); track interest) {
                <span class="interest-tag-preview-pro">
                  {{ interest.trim() }}
                </span>
              }

            } @else {

              <span class="empty-text-italic">
                Aucun centre d'intérêt renseigné.
              </span>

            }

          </div>

        </div>

      </div>

    </div>

  </div>

</div>
```
